import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"DinOdds Plugin","description":"Getting Started with DinOdds Plugin","frontmatter":{"title":"DinOdds Plugin","description":"Getting Started with DinOdds Plugin","weight":40,"extra":{"order":40},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/dinodds/"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/dinodds/"}],["meta",{"property":"og:title","content":"DinOdds Plugin"}],["meta",{"property":"og:description","content":"Getting Started with DinOdds Plugin"}],["meta",{"name":"twitter:title","content":"DinOdds Plugin"}],["meta",{"name":"twitter:description","content":"Getting Started with DinOdds Plugin"}]]},"headers":[],"relativePath":"docs/dinodds/index.md","filePath":"docs/dinodds/index.md"}'),n={name:"docs/dinodds/index.md"};function d(r,e,s,l,h,c){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="dinodds-plugin" tabindex="-1">DinOdds Plugin <a class="header-anchor" href="#dinodds-plugin" aria-label="Permalink to &quot;DinOdds Plugin&quot;">​</a></h1><p>DinOdds lets display odds comparison tables for major leagues on your website super easily, just a couple of clicks.</p><hr><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>It&#39;s easy to get started with DinOdds. Follow the documentations to install and start using the plugin.</p><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><p>Before getting started make sure you have all the requirements met.</p><p>To use the plugin, you must be running <code>WordPress 5.0</code> or higher and <code>PHP 8.4</code> or higher. Recommended <code>WordPress 6.9</code>.</p><p>Also make sure your host has the minimum requirements to run WordPress and PHP <code>max_upload_size</code> is more than 8MB.</p><h3 id="api-subscription" tabindex="-1">API Subscription <a class="header-anchor" href="#api-subscription" aria-label="Permalink to &quot;API Subscription&quot;">​</a></h3><p>To use the plugin you need to have a monthly or yearly subscription and need to adjust your subscription settings.<br> Read more <a href="/docs/dinodds/api">here</a>.</p><h3 id="scheduling" tabindex="-1">Scheduling <a class="header-anchor" href="#scheduling" aria-label="Permalink to &quot;Scheduling&quot;">​</a></h3><p>To be able to display the latest odds feeds, your website needs to pull the data from DinoFeeds API periodically and for this you may have to set up system cron jobs.<br> Read more <a href="/docs/dinodds/scheduling">here</a>.</p><h3 id="demo" tabindex="-1">Demo <a class="header-anchor" href="#demo" aria-label="Permalink to &quot;Demo&quot;">​</a></h3><p>You can check out the plugin on demo website to get ideas how to build your own website - <a href="https://demos.dinomatic.com/luanda" target="_blank" rel="noreferrer">Demo</a></p><h3 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h3><p>Find the full changelog <a href="https://dinomatic.com/plugins/dinodds/changelog" target="_blank" rel="noreferrer">here</a>.</p>',17)])])}const m=t(n,[["render",d]]);export{p as __pageData,m as default};
